import Box from '@mui/material/Box';

function CustomScrollbarBox() {
  return (
    <Box
      sx={{
        height: 200,
        overflowY: 'auto',
        border: '1px solid grey',
        '&::-webkit-scrollbar': {
          width: '10px'
        },
        '&::-webkit-scrollbar-thumb': {
          backgroundColor: '#888',
          borderRadius: '10px'
        }
      }}
    >
      {[...Array(20)].map((_, index) => (
        <p key={index}>Đây là dòng nội dung số {index + 1}</p>
      ))}
    </Box>
  );
}

export default CustomScrollbarBox;

