function HoverableList() {
  return (
    <List sx={{ 
      width: 300, 
      border: '1px solid grey',
      // Nhắm đến ListItemButton và trạng thái hover của nó
      '.MuiListItemButton-root:hover': {
        backgroundColor: '#f0f0f0'
      }
    }}>
      <ListItem disablePadding>
        <ListItemButton>
          <ListItemText primary="Mục 1" />
        </ListItemButton>
      </ListItem>
      <ListItem disablePadding>
        <ListItemButton>
          <ListItemText primary="Mục 2" />
        </ListItemButton>
      </ListItem>
    </List>
  );
}

export default HoverableList;

