import Box from '@mui/material/Box';
import Chip from '@mui/material/Chip';
import Stack from '@mui/material/Stack';

function AdvancedChipStyling() {
  const handleDelete = () => {};

  return (
    <Box sx={{ 
      padding: 2, 
      border: '1px dashed grey',
      // Thay đổi màu icon xóa
      '.MuiChip-deleteIcon': {
        color: 'red'
      },
      // Thay đổi màu nền khi hover
      '.MuiChip-root:hover': {
        backgroundColor: '#e0e0e0'
      }
    }}>
      <Stack direction="row" spacing={1}>
        <Chip label="Apple" onDelete={handleDelete} />
        <Chip label="Banana" onDelete={handleDelete} />
        <Chip label="Cherry" onDelete={handleDelete} />
      </Stack>
    </Box>
  );
}

export default AdvancedChipStyling;
